def generate_vocabulary_files():
    if not os.path.exists(OUTPUT_DIR):
        os.makedirs(OUTPUT_DIR)
    
    total_words = 0
    file_stats = []
    
    for key, words in CET6_VOCABULARY.items():
        filename = f'cet6_vocabulary_{key.lower().replace("-", "")}.json'
        filepath = os.path.join(OUTPUT_DIR, filename)
        
        with open(filepath, 'w', encoding='utf-8') as f:
            json.dump(words, f, ensure_ascii=False, indent=2)
        
        count = len(words)
        total_words += count
        file_stats.append(f'{filename}: {count} words')
        print(f'Generated {filepath} with {count} words')
    
    print(f'\nTotal: {total_words} words across {len(CET6_VOCABULARY)} files')
    for stat in file_stats:
        print(f'  {stat}')

if __name__ == '__main__':
    generate_vocabulary_files()